import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.FieldNamingStrategy;
import com.google.gson.FieldNamingPolicy;
import com.google.gson.Gson;

class GsonFieldNamingStrategyTest {

  @Test
  void testFieldNamingStrategy_Default() {
    Gson gson = new Gson();
    FieldNamingStrategy strategy = gson.fieldNamingStrategy();
    assertNotNull(strategy);
    assertSame(FieldNamingPolicy.IDENTITY, strategy);
  }

  @Test
  void testFieldNamingStrategy_Custom() throws Exception {
    FieldNamingStrategy customStrategy = field -> "customName";
    // Use reflection to create Gson instance with custom fieldNamingStrategy
    Gson gson = createGsonWithFieldNamingStrategy(customStrategy);
    FieldNamingStrategy strategy = gson.fieldNamingStrategy();
    assertNotNull(strategy);
    assertEquals("customName", strategy.translateName(null));
    assertSame(customStrategy, strategy);
  }

  private Gson createGsonWithFieldNamingStrategy(FieldNamingStrategy strategy) throws Exception {
    // Use reflection to invoke the package-private constructor with custom fieldNamingStrategy
    Class<Gson> clazz = Gson.class;
    var constructor = clazz.getDeclaredConstructor(
        com.google.gson.internal.Excluder.class,
        FieldNamingStrategy.class,
        java.util.Map.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        com.google.gson.LongSerializationPolicy.class,
        String.class,
        int.class,
        int.class,
        java.util.List.class,
        java.util.List.class,
        java.util.List.class,
        com.google.gson.ToNumberStrategy.class,
        com.google.gson.ToNumberStrategy.class,
        java.util.List.class);
    constructor.setAccessible(true);

    return constructor.newInstance(
        null, // Excluder excluder
        strategy, // FieldNamingStrategy fieldNamingStrategy
        java.util.Collections.emptyMap(), // instanceCreators
        false, // serializeNulls
        false, // complexMapKeySerialization
        false, // generateNonExecutableGson
        true,  // htmlSafe
        false, // prettyPrinting
        false, // lenient
        false, // serializeSpecialFloatingPointValues
        true,  // useJdkUnsafe
        com.google.gson.LongSerializationPolicy.DEFAULT, // longSerializationPolicy
        null, // datePattern
        2,    // dateStyle
        2,    // timeStyle
        java.util.Collections.emptyList(), // builderFactories
        java.util.Collections.emptyList(), // builderHierarchyFactories
        java.util.Collections.emptyList(), // factoriesToBeAdded
        com.google.gson.ToNumberPolicy.DOUBLE, // objectToNumberStrategy
        com.google.gson.ToNumberPolicy.LAZILY_PARSED_NUMBER, // numberToNumberStrategy
        java.util.Collections.emptyList() // reflectionFilters
    );
  }
}
